  ('hibiscus', 'Hibiscus', 'Hibiscus syriacus', ARRAY['Rose of China', 'Rose of Sharon']::text[], ARRAY['red', 'pink', 'yellow', 'orange']::text[], 'https://upload.wikimedia.org/wikipedia/commons/8/82/Hibiscus_rosa-sinensis_flower_2.JPG', ARRAY['https://upload.wikimedia.org/wikipedia/commons/8/82/Hibiscus_rosa-sinensis_flower_2.JPG', 'https://upload.wikimedia.org/wikipedia/commons/c/cb/Hibiscus_flower_TZ.jpg', 'https://upload.wikimedia.org/wikipedia/commons/2/25/Hibiscus_rosa-sinensis_4.jpg']::text[], 'non_toxic', NULL, NULL),
  ('gerber-daisy', 'Gerber Daisy', 'Gerbera jamesonii', ARRAY['African Daisy', 'Barberton Daisy']::text[], ARRAY['red', 'pink', 'orange', 'yellow', 'white']::text[], 'https://upload.wikimedia.org/wikipedia/commons/1/14/Gerbera_cultivation.JPG', ARRAY['https://upload.wikimedia.org/wikipedia/commons/1/14/Gerbera_cultivation.JPG', 'https://upload.wikimedia.org/wikipedia/commons/5/52/Gerbera_jamesonii_1.jpg', 'https://upload.wikimedia.org/wikipedia/commons/a/a9/Gerbera_jamesonii_cultivar.jpg']::text[], 'non_toxic', NULL, NULL),
  ('begonia', 'Begonia', 'Begonia spp.', ARRAY['Elephant-Ear Begonia', 'Iron Cross Begonia', 'Mapleleaf Begonia', 'Metallic Leaf Begonia', 'Peace Begonia', 'Pink Pearl']::text[], ARRAY['pink', 'red', 'white', 'orange']::text[], 'https://upload.wikimedia.org/wikipedia/commons/2/25/Begonia_coccinea.jpg', ARRAY['https://upload.wikimedia.org/wikipedia/commons/2/25/Begonia_coccinea.jpg', 'https://upload.wikimedia.org/wikipedia/commons/d/df/Begonia_x_semperflorens.jpg', 'https://upload.wikimedia.org/wikipedia/commons/0/0c/Begonia_rex_1.jpg']::text[], 'mildly_toxic', 'Kidney failure (in grazing animals), vomiting, salivation in dogs/cats. Most toxic part is underground.', 'Soluble calcium oxalates'),
  ('chrysanthemum', 'Chrysanthemum', 'Chrysanthemum spp.', ARRAY['Mum']::text[], ARRAY['white', 'yellow', 'pink', 'red', 'orange']::text[], 'https://upload.wikimedia.org/wikipedia/commons/6/61/Chrysanthemum_morifolium.jpg', ARRAY['https://upload.wikimedia.org/wikipedia/commons/6/61/Chrysanthemum_morifolium.jpg', 'https://upload.wikimedia.org/wikipedia/commons/a/af/Chrysanthemum1.jpg', 'https://upload.wikimedia.org/wikipedia/commons/7/7a/Chrysanthemum_November_2007.jpg']::text[], 'mildly_toxic', 'Vomiting, diarrhea, hypersalivation, incoordination, dermatitis', 'Sesquiterpene, lactones, pyrethrins and other potential irritants'),
  ('cyclamen', 'Cyclamen', 'Cyclamen spp', ARRAY['Sowbread']::text[], ARRAY['pink', 'red', 'white', 'purple']::text[], 'https://upload.wikimedia.org/wikipedia/commons/2/2c/Cyclamen_persicum_Mill._01.jpg', ARRAY['https://upload.wikimedia.org/wikipedia/commons/2/2c/Cyclamen_persicum_Mill._01.jpg', 'https://upload.wikimedia.org/wikipedia/commons/a/a3/Cyclamen_hederifolium_%28flower%29.jpg', 'https://upload.wikimedia.org/wikipedia/commons/c/c2/Cyclamen_coum02.jpg']::text[], 'highly_toxic', 'Salivation, vomiting, diarrhea. Following large ingestions of tubers: heart rhythm abnormalities, seizures, death', 'Terpenoid saponins'),
  ('amaryllis', 'Amaryllis', 'Amaryllis spp.', ARRAY['Naked Lady']::text[], ARRAY['red', 'white', 'pink']::text[], 'https://upload.wikimedia.org/wikipedia/commons/4/4a/Hippeastrum_reginae.jpg', ARRAY['https://upload.wikimedia.org/wikipedia/commons/4/4a/Hippeastrum_reginae.jpg', 'https://upload.wikimedia.org/wikipedia/commons/e/eb/Hippeastrum_Red_Lion.jpg', 'https://upload.wikimedia.org/wikipedia/commons/c/c1/Hippeastrum_striatum_1.jpg']::text[], 'mildly_toxic', 'Vomiting (not horses), depression, diarrhea, abdominal pain, hypersalivation, anorexia, tremors.', 'Lycorine and others'),
  ('tulip', 'Tulip', 'Tulipa spp.', ARRAY['Garden Tulip']::text[], ARRAY['red', 'yellow', 'pink', 'purple', 'white', 'orange']::text[], 'https://upload.wikimedia.org/wikipedia/commons/c/cf/Tulip_Tulipa_clusiana_%27Lady_Jane%27_Rock_Ledge_Flower_Edit_2000px.jpg', ARRAY['https://upload.wikimedia.org/wikipedia/commons/c/cf/Tulip_Tulipa_clusiana_%27Lady_Jane%27_Rock_Ledge_Flower_Edit_2000px.jpg', 'https://upload.wikimedia.org/wikipedia/commons/b/b2/Triumph_Tulip_Tulipa_%27Prinses_Irene%27_Single_2859px.jpg', 'https://upload.wikimedia.org/wikipedia/commons/e/ea/Tulipa_suaveolens_floriade_to_Canberra.jpg']::text[], 'mildly_toxic', 'Vomiting, depression, diarrhea, hypersalivation. Highest concentration of toxin in bulb.', 'Tulipalin A and B'),
  ('hyacinth', 'Hyacinth', 'Hyacinthus orientalis', ARRAY['Garden Hyacinth']::text[], ARRAY['purple', 'pink', 'white', 'blue']::text[], 'https://upload.wikimedia.org/wikipedia/commons/a/ae/Garden_Hyacinth_Hyacinthus_orientalis_%27Blue_Jacket%27_Flower_2000px.jpg', ARRAY['https://upload.wikimedia.org/wikipedia/commons/a/ae/Garden_Hyacinth_Hyacinthus_orientalis_%27Blue_Jacket%27_Flower_2000px.jpg', 'https://upload.wikimedia.org/wikipedia/commons/7/7b/Garden_Hyacinth_Hyacinthus_orientalis_%27Purple_Voice%27_Flower_1644px.JPG', 'https://upload.wikimedia.org/wikipedia/commons/3/3c/Hyacinthus_orientalis_Bl%C3%BCte_01.JPG']::text[], 'mildly_toxic', 'Intense vomiting, diarrhea, occassionally with blood, depression and tremors.', 'Possibly narcissus-like alkaloids'),
  ('daffodil', 'Daffodil', 'Narcissus spp', ARRAY['Narcissus', 'Paper White']::text[], ARRAY['yellow', 'white']::text[], 'https://upload.wikimedia.org/wikipedia/commons/2/24/Narcissus_poeticus.jpg', ARRAY['https://upload.wikimedia.org/wikipedia/commons/2/24/Narcissus_poeticus.jpg', 'https://upload.wikimedia.org/wikipedia/commons/c/c5/Narcissus-tazetta-2014-Zachi-Evenor.jpg', 'https://upload.wikimedia.org/wikipedia/commons/2/21/Daffodil_%28Narcissus%29_flower_-_geograph.org.uk_-_4395626.jpg']::text[], 'highly_toxic', 'Vomiting, salvation, diarrhea; large ingestions cause convulsions, low blood pressure, tremors and cardiac arrhythmias. Bulbs are the most poisonous part.', 'Lycorine and other alkaloids'),
  ('lily', 'Lily', 'Lilium species', ARRAY['Asian Lily', 'Easter Lily', 'Japanese Show Lily', 'Red Lily', 'Rubrum Lily', 'Stargazer Lily']::text[], ARRAY['white', 'pink', 'orange', 'yellow']::text[], 'https://upload.wikimedia.org/wikipedia/commons/3/30/Lilium_candidum_1.jpg', ARRAY['https://upload.wikimedia.org/wikipedia/commons/3/30/Lilium_candidum_1.jpg', 'https://upload.wikimedia.org/wikipedia/commons/d/dd/Lilium_longiflorum_%28Easter_Lily%29.JPG', 'https://upload.wikimedia.org/wikipedia/commons/d/d9/Lilium_%27Stargazer%27.jpg']::text[], 'highly_toxic', 'Cats: kidney failure.', NULL),
  ('cast-iron-plant', 'Cast Iron Plant', 'Aspidistra elatior', ARRAY['Bar Room Plant', 'Aspidistra']::text[], ARRAY['green']::text[], 'https://upload.wikimedia.org/wikipedia/commons/8/83/Aspidistra-elatior-variegata.jpg', ARRAY['https://upload.wikimedia.org/wikipedia/commons/8/83/Aspidistra-elatior-variegata.jpg', 'https://upload.wikimedia.org/wikipedia/commons/f/f6/Aspidistra_elatior_Blume_cv.jpg', 'https://upload.wikimedia.org/wikipedia/commons/7/70/Aspidistra_elatior_-_%D0%91%D0%BE%D1%82%D0%B0%D0%BD%D0%B8%D1%87%D0%BA%D0%B0_%D0%B3%D1%80%D0%B0%D0%B4%D0%B8%D0%BD%D0%B0_%D0%A1%D0%BA%D0%BE%D0%BF%D1%98%D0%B5_%281%29.jpg']::text[], 'non_toxic', NULL, NULL),
  ('aluminum-plant', 'Aluminum Plant', 'Pilea cadieri', ARRAY['Watermelon Pilea']::text[], ARRAY['green', 'white']::text[], 'https://upload.wikimedia.org/wikipedia/commons/0/08/Pilea_cadierei.jpg', ARRAY['https://upload.wikimedia.org/wikipedia/commons/0/08/Pilea_cadierei.jpg', 'https://upload.wikimedia.org/wikipedia/commons/3/3f/Pilea_cadierei1.jpg', 'https://upload.wikimedia.org/wikipedia/commons/b/b4/Pilea_cadierei_2zz.jpg']::text[], 'non_toxic', NULL, NULL),
