  ('polka-dot-plant', 'Polka Dot Plant', 'Hypoestes phyllostachya', ARRAY['Baby’s Tears', 'Freckle Face', 'Pink Splash']::text[], ARRAY['pink', 'white', 'red']::text[], 'https://upload.wikimedia.org/wikipedia/commons/4/4c/Hypoestes_phyllostachya_0205.jpg', ARRAY['https://upload.wikimedia.org/wikipedia/commons/4/4c/Hypoestes_phyllostachya_0205.jpg', 'https://upload.wikimedia.org/wikipedia/commons/c/ca/Hypoestes_phyllostachya_0200.jpg', 'https://upload.wikimedia.org/wikipedia/commons/3/30/Hypoestes_phyllostachya_0220.jpg']::text[], 'non_toxic', NULL, NULL),
